DRAW_STARS_BACKGROUND:
    MOVL R7, 2 ; STAR SIZE

    MOVL R8, BRANCO.l
    MOVH R8, BRANCO.h

    ; Linha superior
    MOVL R1, 10
    MOVL R2, 10
    RECT R1, R2, R7, R7, R8

    MOVL R1, 45
    MOVL R2, 25
    RECT R1, R2, R7, R7, R8

    MOVL R1, 80
    MOVL R2, 15
    RECT R1, R2, R7, R7, R8

    MOVL R1, 130
    MOVL R2, 35
