    MOVL R1, 240
    MOVL R2, 40
    RECT R1, R2, R7, R7, R8

    MOVL R1, 300
    MOVL R2, 12
    RECT R1, R2, R7, R7, R8

    ; Linha do meio
    MOVL R1, 25
    MOVL R2, 70
    RECT R1, R2, R7, R7, R8

    MOVL R1, 90
    MOVL R2, 90
    RECT R1, R2, R7, R7, R8

    MOVL R1, 150
    MOVL R2, 75
    RECT R1, R2, R7, R7, R8

    MOVL R1, 210
    MOVL R2, 100
    RECT R1, R2, R7, R7, R8

    MOVL R1, 280
    MOVL R2, 65
    RECT R1, R2, R7, R7, R8

    ; Próximo ao horizonte
    MOVL R1, 40
    MOVL R2, 130
    RECT R1, R2, R7, R7, R8

    MOVL R1, 100
    MOVL R2, 145
    RECT R1, R2, R7, R7, R8

    MOVL R1, 170
    MOVL R2, 120
    RECT R1, R2, R7, R7, R8

    MOVL R1, 230
    MOVL R2, 150
    RECT R1, R2, R7, R7, R8

    MOVL R1, 295
    MOVL R2, 135
    RECT R1, R2, R7, R7, R8

    MOVL R5, 80            ; x = 160
    MOVL R6, 60            ; y = 120
    MOVL R7, msg.l          ; endereço da string (parte baixa)
    MOVH R7, msg.h          ; endereço da string (parte alta)
    MOVL R8, AZUL.l         ; color = branco (ARGB)
    MOVH R8, AZUL.h         ; color = branco (ARGB)
    PSTR R5, R6, R7, R8 

    MOVL R3, 4
    SYSCALL R3, R0,R0,R0,R0

    
    

GAME:

    ; CALL DRAW_STARS_BACKGROUND

    ; CLEAN FRAME COUNTER FOR NEXT FRAME
    MOVL R1, 10        
    MOVL R2, 10          
    MOVL R3, 48
    MOVL R4, 16  
    MOVL R5, PRETO.l         
    MOVH R5, PRETO.h         
    RECT R1, R2, R3, R4, R5

    ; FRAME COUNTER
    FRAMENUM R4
    MOVL R1, 10
    MOVL R2, 10
    MOVL R3, AMARELO.l       
    MOVH R3, AMARELO.h         
    PINT R1, R2, R4, R3

    ; FPS SYNC
    MOVL R4, frame_counter.l
    MOVH R4, frame_counter.h
    LOAD R3, R4, 0       ; R3 = Guarda o último frame em que a nave se moveu
    FRAMENUM R5          ; R5 = Pega o frame atual do relógio
    BEQ R3, R5, GAME     ; Se o frame for igual, volta pro começo (espera!)

    ; Se passou do BEQ, significa que o frame mudou (1/60 de segundo se passou!)
    STORE R5, R4, 0      ; Atualiza o frame_counter com o novo frame

    MOVE_PLAYER:
        ;; PLAYER POSITION 
        MOVL R6, player_x.l
        MOVH R6, player_x.h
        LOAD R1, R6, 0

        MOVL R7, player_y.l
        MOVH R7, player_y.h
        LOAD R2, R7, 0

        ;; Clean old ship
        MOVL R3, 16
        MOVL R4, 16
        MOVL R5, PRETO.l
        MOVH R5, PRETO.h
        RECT R1, R2, R3, R4, R5

        LEFT_ARROW: 
            MOVL R3, LEFT_ARROW_KEYCODE
            GKEY R4, R3
            BEQ R4, R0, RIGHT_ARROW
            ; LEFET LIMIT 
            BEQ R1, R0, RIGHT_ARROW
            DEC R1

        RIGHT_ARROW: 
            MOVL R3, RIGHT_ARROW_KEYCODE
            GKEY R4, R3
            BEQ R4, R0, UP_ARROW
            ; RIGHT LIMIT 
            MOVL R8, 304
            BGE R1, R8, UP_ARROW
            INC R1

        UP_ARROW: 
            MOVL R3, UP_ARROW_KEYCODE
            GKEY R4, R3
            BEQ R4, R0, DOWN_ARROW
            ; UP LIMIT 
            BEQ R2, R0, DOWN_ARROW
            DEC R2

        DOWN_ARROW: 
            MOVL R3, DOWN_ARROW_KEYCODE
            GKEY R4, R3
            BEQ R4, R0, DRAW_SPACE_SHIP
            ; DOWN LIMIT
            MOVL R8, 224
            BGE R2, R8, DRAW_SPACE_SHIP
            INC R2

        DRAW_SPACE_SHIP: 
            STORE R1, R6, 0
            STORE R2, R7, 0 
            
            ; DRAW SPACE SHIP
            MOVL R3, 16
            MOVL R4, 16
            MOVL R5, ship_sprite.l
            MOVH R5, ship_sprite.h
            DSPRITE R1, R2, R3, R4, R5       ; Desenha na nova coordenada
        
    BEQ R0, R0, DRAW_STARS_BACKGROUND ; infinite loop


